def nrm(s):
    return normalize(s)
def lcs_ratio(a, b):
    # compute length of LCS divided by average length
    A=list(a)
    B=list(b)
    # dynamic programming
    na, nb = len(A), len(B)
    dp = [[0]*(nb+1) for _ in range(na+1)]
    for i in range(1, na+1):
        ai=A[i-1]
        for j in range(1, nb+1):
            if ai==B[j-1]:
                dp[i][j]=dp[i-1][j-1]+1
            else:
                dp[i][j]=dp[i-1][j] if dp[i-1][j]>=dp[i][j-1] else dp[i][j-1]
    lcs=dp[na][nb]
    return lcs / ((na+nb)/2.0)

